files.content:
* { box-sizing: border-box; }

body {
  margin: 0;
  font-family: 'Segoe UI', sans-serif;
  background: #f2f4f7;
  color: #0e1a22;
}

main {
  width: min(860px, 92vw);
  margin: 2rem auto;
  padding: 1.25rem;
  border-radius: 0.9rem;
  background: #ffffff;
  box-shadow: 0 10px 28px rgba(8, 24, 38, 0.1);
}

h1 {
  margin-top: 0;
}

button {
  border: 0;
  border-radius: 0.6rem;
  padding: 0.6rem 0.9rem;
  background: #f3ad3b;
  color: #121212;
  font-weight: 700;
  cursor: pointer;
}

const checkButton = document.getElementById('check-btn');
const status = document.getElementById('status');

checkButton?.addEventListener('click', () => {
  if (!status) return;
  status.textContent = 'Status: Færdig - du har gennemført filtype introen.';
});
